describe('webview/legends/section', () => {
  const baseProps = {
    title: 'Nodes',
    builtInEntries: [{ id: 'file', label: 'Files', color: '#111111' }],
    displayRules: [
      { id: 'node:user', pattern: 'src/**', color: '#123456', target: 'node' },
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
      {
        id: 'node:plugin',
        pattern: '*.ts',
        color: '#3178c6',
        target: 'node',
        isPluginDefault: true,
      },
    ] as IGroup[],
    userRules: [
      { id: 'node:user', pattern: 'src/**', color: '#123456', target: 'node' },
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
      { id: 'edge:user', pattern: 'call', color: '#654321', target: 'edge' },
    ] as IGroup[],
    legends: [
      { id: 'node:user', pattern: 'src/**', color: '#123456', target: 'node' },
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
      { id: 'edge:user', pattern: 'call', color: '#654321', target: 'edge' },
    ] as IGroup[],
    target: 'node' as const,
    onBuiltInColorChange: vi.fn(),
    onRulesChange: vi.fn(),
    onToggleDefaultVisibility: vi.fn(),
  };

  it('renders rows and collapses the section body', () => {
    render(<LegendSection {...baseProps} />);

    expect(screen.getByText('built-in:Files')).toBeInTheDocument();
    expect(screen.getByText('src/**')).toBeInTheDocument();

    fireEvent.click(screen.getByTitle('Toggle Nodes legend section'));

    expect(screen.queryByText('built-in:Files')).not.toBeInTheDocument();
    expect(screen.queryByText('src/**')).not.toBeInTheDocument();
  });

  it('forwards built-in color changes, added rules, and rule updates to the section callbacks', () => {
    render(<LegendSection {...baseProps} />);

    fireEvent.click(screen.getByText('built-in:Files'));
    expect(baseProps.onBuiltInColorChange).toHaveBeenCalledWith('file', '#abc123');

    fireEvent.click(screen.getByText('add:node'));
    expect(baseProps.onRulesChange).toHaveBeenCalledWith([
      { id: 'node:user', pattern: 'src/**', color: '#123456', target: 'node' },
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
      { id: 'edge:user', pattern: 'call', color: '#654321', target: 'edge' },
      { id: 'legend:node:new', pattern: 'node/**', color: '#00ff00', target: 'node' },
    ]);

    fireEvent.click(screen.getByText('change:node:user'));
    expect(baseProps.onRulesChange).toHaveBeenCalledWith([
      { id: 'node:user', pattern: 'src/**:updated', color: '#123456', target: 'node' },
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
    ]);
  });

  it('removes rules and forwards plugin-default visibility toggles', () => {
    render(<LegendSection {...baseProps} />);

    fireEvent.click(screen.getByText('remove:node:user'));
    expect(baseProps.onRulesChange).toHaveBeenCalledWith([
      { id: 'node:second', pattern: 'tests/**', color: '#456789', target: 'node' },
      { id: 'edge:user', pattern: 'call', color: '#654321', target: 'edge' },
    ]);

    fireEvent.click(screen.getByText('toggle:node:plugin'));
    expect(baseProps.onToggleDefaultVisibility).toHaveBeenCalledWith('node:plugin', false);
  });

  it('posts rule reorders only after a drag starts and clears the drag state after the drop', () => {
    render(<LegendSection {...baseProps} />);

    fireEvent.click(screen.getByText('drop:node:user'));
    expect(postLegendOrderUpdate).not.toHaveBeenCalled();

    fireEvent.click(screen.getByText('drag-start:node:plugin'));
    expect(screen.getByTestId('legend-row-node:plugin')).toHaveAttribute('data-dragging', 'true');
    fireEvent.click(screen.getByText('drag-over:node:user'));
    expect(screen.getByTestId('legend-row-node:user')).toHaveAttribute('data-drag-over', 'true');
    fireEvent.click(screen.getByText('drop:node:user'));

    expect(postLegendOrderUpdate).toHaveBeenCalledWith(
      baseProps.displayRules,
      baseProps.legends,
      'node',
      2,
      0,
    );
    expect(screen.getByTestId('legend-row-node:plugin')).toHaveAttribute('data-dragging', 'false');
    expect(screen.getByTestId('legend-row-node:user')).toHaveAttribute('data-drag-over', 'false');

    fireEvent.click(screen.getByText('drop:node:user'));
    expect(postLegendOrderUpdate).toHaveBeenCalledTimes(1);

    fireEvent.click(screen.getByText('drag-start:node:plugin'));
    fireEvent.click(screen.getByText('drag-over:node:user'));
    fireEvent.click(screen.getByText('drag-end:node:plugin'));
    expect(screen.getByTestId('legend-row-node:plugin')).toHaveAttribute('data-dragging', 'false');
    expect(screen.getByTestId('legend-row-node:user')).toHaveAttribute('data-drag-over', 'false');
  });
});

import React from 'react';
import { fireEvent, render, screen } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { LegendRuleRow } from '../../../src/webview/components/legends/ruleRow';

vi.mock('../../../src/webview/components/legends/colorInput', () => ({
  LegendColorInput: ({
    ariaLabel,
    color,
    onCommit,
  }: {
    ariaLabel: string;
    color: string;
    onCommit: (color: string) => void;
  }) => (
    <button aria-label={ariaLabel} data-color={color} onClick={() => onCommit('#654321')} type="button">
      color
    </button>
  ),
}));

const baseHandlers = () => ({
  onDragStart: vi.fn(),
  onDragOver: vi.fn(),
  onDrop: vi.fn(),
  onDragEnd: vi.fn(),
  onChange: vi.fn(),
  onRemove: vi.fn(),
  onToggleDefaultVisibility: vi.fn(),
});

describe('webview/components/legends/ruleRow', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders editable custom rules and routes edits through onChange/onRemove', () => {
    const handlers = baseHandlers();
    render(
      <LegendRuleRow
        rule={{ id: 'legend:custom', pattern: 'src/**', color: '#123456', target: 'node' }}
        index={0}
        isDragging={true}
        isDragOver={true}
        {...handlers}
      />,
    );

    fireEvent.change(screen.getByLabelText('Legend pattern 1'), { target: { value: 'tests/**' } });
    fireEvent.click(screen.getByLabelText('Legend color 1'));
    fireEvent.click(screen.getByRole('switch'));
    fireEvent.click(screen.getByTitle('Delete legend rule'));

    expect(handlers.onChange).toHaveBeenNthCalledWith(1, {
      id: 'legend:custom',
      pattern: 'tests/**',
      color: '#123456',
      target: 'node',
    });
    expect(handlers.onChange).toHaveBeenNthCalledWith(2, {
      id: 'legend:custom',
      pattern: 'src/**',
      color: '#654321',
      target: 'node',
    });
    expect(handlers.onChange).toHaveBeenNthCalledWith(3, {
      id: 'legend:custom',
      pattern: 'src/**',
      color: '#123456',
      target: 'node',
      disabled: true,
    });
    expect(handlers.onRemove).toHaveBeenCalledOnce();
    expect(screen.getByTestId('legend-rule-row').className).toBe(
      'transition-colors bg-accent/30 opacity-60',
    );
  });

  it('renders plugin defaults as read-only and toggles visibility through the default handler', () => {
    const handlers = baseHandlers();
    const { container } = render(
      <LegendRuleRow
        rule={{
          id: 'legend:default',
          pattern: '*.ts',
          color: '#abcdef',
          target: 'node',
          isPluginDefault: true,
          disabled: true,
        }}
        index={1}
        isDragging={false}
        isDragOver={false}
        {...handlers}
      />,
    );

    expect(screen.queryByLabelText('Legend pattern 2')).toBeNull();
    expect(screen.queryByLabelText('Legend color 2')).toBeNull();
    expect(screen.queryByTitle('Delete legend rule')).toBeNull();
    expect(screen.getByTitle('*.ts')).toHaveTextContent('*.ts');
    expect(screen.getByTestId('legend-rule-row').className).toBe('transition-colors');
    expect(container.querySelector('span[aria-hidden="true"]')).toHaveStyle({ backgroundColor: '#abcdef' });
    fireEvent.click(screen.getByRole('switch'));

    expect(handlers.onToggleDefaultVisibility).toHaveBeenCalledWith('legend:default', true);
    expect(handlers.onChange).not.toHaveBeenCalled();
  });
});

import React from 'react';
import { fireEvent, render, screen } from '@testing-library/react';
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import { LegendColorInput } from '../../../src/webview/components/legends/colorInput';

describe('webview/components/legends/colorInput', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('debounces color commits and only flushes the latest pending value', () => {
    const onCommit = vi.fn();
    const clearTimeoutSpy = vi.spyOn(globalThis, 'clearTimeout');
    render(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#112233"
        onCommit={onCommit}
      />,
    );

    const input = screen.getByLabelText('Legend color');
    fireEvent.change(input, { target: { value: '#223344' } });
    fireEvent.change(input, { target: { value: '#334455' } });
    expect(clearTimeoutSpy).toHaveBeenCalledTimes(1);
    vi.advanceTimersByTime(149);
    expect(onCommit).not.toHaveBeenCalled();
    vi.advanceTimersByTime(1);

    expect(onCommit).toHaveBeenCalledTimes(1);
    expect(onCommit).toHaveBeenCalledWith('#334455');
    expect((input as HTMLInputElement).value).toBe('#334455');
  });

  it('flushes pending changes on blur and commits immediately when configured', () => {
    const onCommit = vi.fn();
    const clearTimeoutSpy = vi.spyOn(globalThis, 'clearTimeout');
    const { rerender } = render(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#112233"
        onCommit={onCommit}
      />,
    );

    const input = screen.getByLabelText('Legend color');
    fireEvent.change(input, { target: { value: '#445566' } });
    fireEvent.blur(input);
    vi.runAllTimers();

    expect(onCommit).toHaveBeenCalledTimes(1);
    expect(onCommit).toHaveBeenCalledWith('#445566');
    expect(clearTimeoutSpy).toHaveBeenCalled();

    rerender(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#445566"
        onCommit={onCommit}
      />,
    );

    fireEvent.blur(screen.getByLabelText('Legend color'));
    expect(onCommit).toHaveBeenCalledTimes(1);

    rerender(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#778899"
        onCommit={onCommit}
        immediate
      />,
    );

    const immediateInput = screen.getByLabelText('Legend color');
    expect((immediateInput as HTMLInputElement).value).toBe('#778899');
    expect(immediateInput.parentElement).toHaveStyle({ backgroundColor: '#778899' });

    fireEvent.change(immediateInput, { target: { value: '#99aabb' } });
    vi.runAllTimers();

    expect(onCommit).toHaveBeenCalledTimes(2);
    expect(onCommit).toHaveBeenLastCalledWith('#99aabb');
  });

  it('clears pending timeouts on unmount', () => {
    const onCommit = vi.fn();
    const clearTimeoutSpy = vi.spyOn(globalThis, 'clearTimeout');
    const firstRender = render(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#112233"
        onCommit={onCommit}
      />,
    );

    firstRender.unmount();
    expect(clearTimeoutSpy).not.toHaveBeenCalled();

    const secondRender = render(
      <LegendColorInput
        ariaLabel="Legend color"
        color="#112233"
        onCommit={onCommit}
      />,
    );

    fireEvent.change(screen.getByLabelText('Legend color'), { target: { value: '#abcdef' } });
    secondRender.unmount();
    vi.runAllTimers();

    expect(clearTimeoutSpy).toHaveBeenCalled();
    expect(onCommit).not.toHaveBeenCalled();
  });
});

